// teuer, ohne Limit ein DoS-Vektor.
AnazhRealm.P2P_BUNDLE_PULL_COOLDOWN_MS = 5000;
// W16-Politur вҖ” der weiche Pull-Timeout: hГӨngt ein Welt-BГјndel-Pull lГӨnger
// als das, gibt _p2pCheckBundlePullTimeout ihn frei (der Sender verschwand
// vermutlich mitten im Chunk-Strom). 30 s вҖ” grosszГјgig fГјr ein Text-Welt-
// BГјndel Гјber einen DataChannel.
AnazhRealm.P2P_BUNDLE_PULL_TIMEOUT_MS = 30000;

// W7 Phase 3 вҖ” LLM-Pool. Ein Peer mit aktivem LLM teilt seine вҖһStimme",
